INSERT INTO `product` (`id`, `title`, `image`, `description`, `content`, `sell`, `view`, `rating`, `status`, `priority`, `tags`, `template`, `stock_manage`, `stop_selling`, `stock_quant`, `option_1`, `option_2`, `option_3`, `option_4`, `option_5`, `option_6`, `created_at`, `updated_at`, `raw_title`, `raw_full`) VALUES
(332, 'HyperX Alloy Origins Core', 'HyperX Alloy Origins Core.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'hyperx alloy origins core', 'hyperx alloy origins core bàn phím chơi game không phím nhỏ gọn có công tắc cơ học hyperx, thân máy hoàn toàn bằng nhôm cấp máy bay, tùy chỉnh ánh sáng rgb, cáp usb-c có thể tháo rời, hỗ trợ chống bóng mờ và độ bền mạnh mẽ cho môi trường chơi game cạnh tranh.'),
(333, 'Logitech G213 Prodigy', 'Logitech G213 Prodigy.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'logitech g213 prodigy', 'logitech g213 prodigy bàn phím chơi game giá cả phải chăng có vùng rgb lightsync, cấu trúc chống tràn, phần tựa tay tích hợp, điều khiển phương tiện chuyên dụng, các phím chơi game màng được điều chỉnh để phản hồi và bố cục kích thước đầy đủ thoải mái để chơi game và sử dụng hàng ngày.'),
(334, 'Logitech G Pro X Superlight 2', 'Logitech G Pro X Superlight 2.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'logitech g pro x superlight 2', 'logitech g pro x superlight 2 chuột chơi game thể thao điện tử chuyên nghiệp được thiết kế để mang lại hiệu suất cạnh tranh siêu nhẹ. có cảm biến quang học hero 2, lên đến 32.000 dpi, kết nối không dây lightspeed, hỗ trợ thăm dò 4k/8k, thiết kế siêu nhẹ 60g, sạc usb-c, chân ptfe và công nghệ không dây có độ trễ thấp tiên tiến được các vận động viên thể thao điện tử chuyên nghiệp trên toàn thế giới tin tưởng.'),
(335, 'Razer Viper V3 Pro', 'Razer Viper V3 Pro.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'razer viper v3 pro', 'razer viper v3 pro chuột chơi game thể thao điện tử không dây cao cấp có cảm biến quang học focus pro 35k, thiết kế công thái học siêu nhẹ, công nghệ không dây hyperspeed, công tắc chuột quang gen-3, tốc độ bỏ phiếu lên đến 8000hz, thời lượng pin dài và độ chính xác chơi game fps cấp độ chuyên nghiệp.'),
(336, 'Logitech G502 X Lightspeed', 'Logitech G502 X Lightspeed.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'logitech g502 x lightspeed', 'logitech g502 x lightspeed một trong những con chuột chơi game được công nhận nhất thế giới có công tắc quang-cơ lai lightforce, cảm biến hero 25k, cài đặt dpi có thể tùy chỉnh, thiết kế tiện dụng, kết nối lightspeed không dây, các nút có thể lập trình, hỗ trợ rgb và tính linh hoạt chơi game đa thể loại.'),
(337, 'Logitech MX Master 3S', 'Logitech MX Master 3S.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'logitech mx master 3s', 'logitech mx master 3s chuột văn phòng và năng suất cao cấp được thiết kế cho quy trình làm việc chuyên nghiệp và đa nhiệm. có thiết kế điêu khắc tiện dụng, cuộn điện từ magspeed, nhấp chuột im lặng, cảm biến darkfield 8000 dpi, sạc nhanh usb-c, kết nối đa thiết bị bluetooth và khả năng tương thích với hệ thống windows và macos.'),
(338, 'Razer DeathAdder V3 Pro', 'Razer DeathAdder V3 Pro.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'razer deathadder v3 pro', 'razer deathadder v3 pro chuột chơi game công thái học nhẹ có cảm biến quang học focus pro 30k, công tắc quang học gen-3, công nghệ hyperspeed không dây, thiết kế siêu nhẹ, hình dạng thuận tay phải tiện dụng và độ chính xác theo dõi cấp thể thao điện tử để chơi game fps và moba.'),
(339, 'Logitech M720 Triathlon', 'Logitech M720 Triathlon.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'logitech m720 triathlon', 'logitech m720 triathlon chuột văn phòng không dây phổ biến được thiết kế cho năng suất và quy trình làm việc đa thiết bị. có kết nối không dây bluetooth và usb, các nút có thể lập trình, tiện nghi về mặt công thái học, chuyển đổi đa thiết bị, thời lượng pin dài, cuộn chính xác và hiệu suất văn phòng đáng tin cậy.'),
(340, 'SteelSeries Rival 3 Wireless', 'SteelSeries Rival 3 Wireless.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'steelseries rival 3 wireless', 'steelseries rival 3 wireless chuột chơi game giá cả phải chăng có cảm biến quang học truemove air, kết nối không dây kép, hiệu suất chơi game có độ trễ thấp, kết cấu nhẹ, ánh sáng rgb, thời lượng pin dài và công tắc bền phù hợp để chơi game và sử dụng máy tính để bàn hàng ngày.'),
(341, 'ASUS TUF Gaming M4 Wireless', 'ASUS TUF Gaming M4 Wireless.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'asus tuf gaming m4 wireless', 'asus tuf gaming m4 wireless chuột chơi game không dây bền bỉ được thiết kế cho hiệu suất chơi game cạnh tranh. có cảm biến quang học 12.000 dpi, thiết kế thuận cả hai tay nhẹ, các nút có thể lập trình, kết nối không dây và bluetooth, hỗ trợ asus aura sync rgb và độ bền lấy cảm hứng từ quân đội.'),
(342, 'Corsair Ironclaw RGB Wireless', 'Corsair Ironclaw RGB Wireless.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'corsair ironclaw rgb wireless', 'corsair ironclaw rgb wireless chuột chơi game tiện dụng được thiết kế cho người chơi fps và moba. có cảm biến quang học 18.000 dpi, công nghệ slipstream không dây, vùng chiếu sáng rgb, các nút có thể lập trình, công tắc omron bền, bề mặt tay cầm có kết cấu và thiết kế tiện dụng bằng tay lớn thoải mái.'),
(343, 'Microsoft Bluetooth Ergonomic Mouse', 'Microsoft Bluetooth Ergonomic Mouse.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'microsoft bluetooth ergonomic mouse', 'microsoft bluetooth ergonomic mouse chuột không dây công thái học tập trung vào văn phòng được thiết kế cho các phiên làm việc lâu dài và môi trường làm việc chuyên nghiệp. có kết nối bluetooth, phần tựa ngón tay cái tiện dụng, cảm biến theo dõi mượt mà, thiết kế nhẹ tập trung vào sự thoải mái, khả năng tương thích đa nền tảng và hiệu quả pin lâu dài.'),
(344, 'NVIDIA GeForce RTX 4060', 'NVIDIA GeForce RTX 4060.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'nvidia geforce rtx 4060', 'nvidia geforce rtx 4060 card đồ họa chơi game chính thống được mua rộng rãi được thiết kế để chơi game mượt mà 1080p và 1440p cấp thấp. có kiến trúc nvidia ada lovelace, bộ nhớ 8gb gddr6, tạo khung hình dlss 3 ai, hỗ trợ dò tia, giao diện pcie 4.0, đầu ra hdmi 2.1 và displayport 1.4a, tiêu thụ điện năng 115w thấp và hiệu quả tuyệt vời cho pc chơi game và sáng tạo nội dung.'),
(345, 'NVIDIA GeForce RTX 4070 SUPER', 'NVIDIA GeForce RTX 4070 SUPER.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'nvidia geforce rtx 4070 super', 'nvidia geforce rtx 4070 super gpu chơi game hiệu năng cao được tối ưu hóa cho khối lượng công việc chơi game và người sáng tạo siêu 1440p. có bộ nhớ gddr12x 6gb, kiến trúc ada lovelace, hỗ trợ dlss 3, lõi dò tia tiên tiến, giao diện pcie 4.0, hỗ trợ mã hóa av1, số lượng lõi cuda cao và hiệu suất tản nhiệt hiệu quả cho pc chơi game đam mê.'),
(346, 'NVIDIA GeForce RTX 4080 SUPER', 'NVIDIA GeForce RTX 4080 SUPER.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'nvidia geforce rtx 4080 super', 'nvidia geforce rtx 4080 super card đồ họa đẳng cấp dành cho người đam mê được thiết kế để chơi game 1440p và 4k tốc độ làm mới cao. có bộ nhớ gddr16x 6gb, kiến trúc ada lovelace tiên tiến, thế hệ dlss 3 khung hình, hiệu suất dò tia cao cấp, kết xuất tăng cường ai, kết nối pcie 4.0 và các giải pháp tản nhiệt mạnh mẽ từ các thương hiệu hàng đầu như asus, msi và gigabyte.'),
(347, 'NVIDIA GeForce RTX 3060', 'NVIDIA GeForce RTX 3060.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'nvidia geforce rtx 3060', 'nvidia geforce rtx 3060 card đồ họa tầm trung cực kỳ phổ biến được sử dụng rộng rãi cho các hệ thống chơi game, phát trực tuyến và năng suất. có kiến trúc ampere, bộ nhớ gddr12 6gb, hỗ trợ dò tia, nâng cấp dlss ai, hỗ trợ pcie 4.0, kết nối hdmi 2.1 và hiệu suất chơi game 1080p đáng tin cậy với giá trị đồng tiền bát gạo.'),
(348, 'NVIDIA GeForce RTX 4090', 'NVIDIA GeForce RTX 4090.jpg', '', '', 0, 0, 0.00, 'active', 1000, 'linh-kien', '', 0, 'publish', 1, '', '', '', '', '', '', '2024-05-14 04:20:00', '2024-05-14 04:20:00', 'nvidia geforce rtx 4090', 'nvidia geforce rtx 4090 card đồ họa nvidia hàng đầu được thiết kế để chơi game 4k cực cao, khối lượng công việc ai, kết xuất chuyên nghiệp và hệ thống máy trạm cao cấp. có bộ nhớ gddr24x 6gb, kiến trúc ada lovelace, lõi dò tia tiên tiến, công nghệ dlss 3, số lượng lõi cuda khổng lồ, giao diện pcie 4.0 và hiệu suất tăng tốc ai và chơi game hàng đầu trong ngành.');;
